#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; if(scanf("%d",&N)!=1) return 0;
        unsigned long long a=0,b=1;
        for(int i=0;i<N;++i){
            if(i==0) printf("%llu",a);
            else if(i==1) printf(" %llu",b);
            else{ unsigned long long c=a+b; printf(" %llu",c); a=b; b=c; }
        }
        printf("\n");
    }
    return 0;
}

