import sys

def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    t=int(data[0])
    idx=1
    out_lines=[]
    for _ in range(t):
        n=int(data[idx]); idx+=1
        a,b=0,1
        line=[]
        for i in range(n):
            if i==0:
                line.append(str(a))
            elif i==1:
                line.append(str(b))
            else:
                c=a+b
                line.append(str(c))
                a,b=b,c
        out_lines.append(' '.join(line))
    sys.stdout.write('\n'.join(out_lines))

if __name__=='__main__':
    solve()

